SOURCE = '            "duplicate_or_sparse_noise": bool(duplicate_or_sparse_noise),\n            "strict_noise_block": bool(strict_noise_block),\n            "transition_warning": bool(transition_warning),\n            "before": before,\n            "after": after,\n            "deltas": {\n                "move_%": dmove, "dve_%": ddve, "rising_eff_%": drise,\n                "falling_eff_drop_%": dfall_drop, "fat_tail_z": dfat,\n                "kurtosis": dk, "kurtosis_ratio": round(k_ratio, 3),\n                "buy_%": dbuy, "sell_%": dsell, "sell_weakness_%": dsell_weak,\n                "trust_%": dtrust,\n            },\n            "drivers": rows,\n        }\n\n    def _history_df(df=None, days=25):\n        try:\n            if df is None:\n                for key in ("last_df", "shared_df", "doo_prime_df", "market_df", "df"):\n                    obj = st.session_state.get(key)\n                    if isinstance(obj, pd.DataFrame) and not obj.empty:\n                        df = obj\n                        break\n            if not callable(_normalize_local):\n                return pd.DataFrame()\n            d = _normalize_local(df).dropna(subset=["time", "close"]).sort_values("time").reset_index(drop=True)\n            if d.empty:\n                return pd.DataFrame()\n            max_t = pd.to_datetime(d["time"], errors="coerce").max()\n            if pd.isna(max_t):\n                return pd.DataFrame()\n            start_t = pd.Timestamp(max_t).normalize() - pd.Timedelta(days=max(1, int(days)) - 1)\n            return d[d["time"] >= start_t].copy().reset_index(drop=True)\n        except Exception:\n            return pd.DataFrame()\n\n    def _actual_interval(d):\n        try:\n            return _finder_actual_interval_minutes(d) if callable(_finder_actual_interval_minutes) else "unknown"\n        except Exception:\n            return "unknown"\n\n    def _pair_for_target(d, target_start):\n        if not callable(_normalize_local):\n            return pd.DataFrame(), pd.DataFrame(), "none"\n        d = _normalize_local(d).dropna(subset=["time", "close"]).sort_values("time").reset_index(drop=True)\n        if d.empty or len(d) < 4:\n            return pd.DataFrame(), pd.DataFrame(), "none"\n        target_start = pd.Timestamp(target_start).floor("h")\n        interval = _actual_interval(d)\n        if interval == "H1-like":\n            pre_n, post_n, mode = 12, 12, "h1_12_before_vs_12_from_target"\n        else:\n            pre_n, post_n, mode = 60, 60, "m1_60_before_vs_60_from_target"\n\n        pre = d[d["time"] < target_start].tail(pre_n)\n        post = d[d["time"] >= target_start].head(post_n)\n        if len(pre) >= 2 and len(post) >= 2:\n            return pre, post, mode\n\n        # Sparse fallback using index nearest target.\n        idxs = d.index[d["time"].dt.floor("h") >= target_start].tolist()\n        idx = int(idxs[0]) if idxs else len(d) - 1\n        block = 12 if interval == "H1-like" else 30\n        pre = d.iloc[max(0, idx - block):idx]\n        post = d.iloc[idx:min(len(d), idx + block)]\n        if len(pre) >= 2 and len(post) >= 2:\n            return pre, post, f"{interval}_nearest_block"\n        return pd.DataFrame(), pd.DataFrame(), str(interval)\n\n    def _engine_from_pair(pre, post, label=None, extra=None):\n        if not callable(_finder_market_snapshot):\n            return None\n        eng = _enhanced_reversal_eval(_finder_market_snapshot(pre), _finder_market_snapshot(post))\n        if label:\n            eng["period_label"] = label\n        eng["source_frame"] = "FULL_CORRECT_10_POINT_CONTEXT_ENGINE"\n        if extra:\n            eng.update(extra)\n        return eng\n\n    def _evaluate_latest(df=None):\n        try:\n            d = _history_df(df=df, days=3)\n            if d.empty or len(d) < 8:\n                return None\n            max_t = pd.to_datetime(d["time"], errors="coerce").max()\n            latest_hour = pd.Timestamp(max_t).floor("h")\n            # If current hour is still very early, use previous completed hour.\n            if pd.Timestamp(max_t) < latest_hour + pd.Timedelta(minutes=20):\n                latest_hour -= pd.Timedelta(hours=1)\n            pre, post, mode = _pair_for_target(d, latest_hour)\n            if len(pre) < 2 or len(post) < 2:\n                return None\n            eng = _engine_from_pair(pre, post, f"Latest context from {latest_hour.strftime(\'%Y-%m-%d %H:00\')}", {\n                "period_time": latest_hour.strftime("%Y-%m-%d %H:%M"),\n                "period_day": latest_hour.strftime("%A"),\n                "scan_mode": mode,\n                "scan_rows": int(len(d)),\n            })\n            st.session_state["last_reversal_engine"] = eng\n            return eng\n        except Exception:\n            return None\n\n    def _find_last(df=None, min_count=7, days=25, return_best=True):\n        try:\n            d = _history_df(df=df, days=days)\n            if d.empty or len(d) < 8:\n                return None\n            max_t = pd.to_datetime(d["time"], errors="coerce").max()\n            if pd.isna(max_t):\n                return None\n            latest_completed = pd.Timestamp(max_t).floor("h")\n            if pd.Timestamp(max_t) < latest_completed + pd.Timedelta(minutes=20):\n                latest_completed -= pd.Timedelta(hours=1)\n            hours = (pd.to_datetime(d["time"], errors="coerce").dt.floor("h")\n                     .dropna().drop_duplicates().sort_values().tolist())\n            hours = [pd.Timestamp(h) for h in hours if pd.Timestamp(h) <= latest_completed]\n            best = None\n            latest_exact = None\n            for h in reversed(hours):\n                pre, post, mode = _pair_for_target(d, h)\n                if len(pre) < 2 or len(post) < 2:\n                    continue\n                eng = _engine_from_pair(pre, post, _format_reversal_period_label(h), {\n                    "period_time": h.strftime("%Y-%m-%d %H:%M"),\n                    "period_day": h.strftime("%A"),\n                    "scan_days": int(days),\n                    "scan_rows": int(len(d)),\n                    "scan_mode": mode,\n                    "is_exact_threshold_match": False,\n                })\n                if not eng:\n                    continue\n                eng["is_exact_threshold_match"] = int(eng.get("active_count", 0)) >= int(min_count)\n                sort_key = (int(eng.get("active_count", 0)), float(eng.get("weighted_score", 0)), h.timestamp())\n                if best is None or sort_key > best["_sort_key"]:\n                    best = {**eng, "_sort_key": sort_key}\n                if eng["is_exact_threshold_match"]:\n                    latest_exact = eng\n                    break\n            out = latest_exact or (best if return_best else None)\n            if out and "_sort_key" in out:\n                out = dict(out)\n                out.pop("_sort_key", None)\n            return out\n        except Exception:\n            return None\n\n    def _finder_detector(results, target_start, target_end):\n        rows = []\n        for key, res in (results or {}).items():\n            label = str(res.get("label", key))\n            context = res.get("context_candles")\n            if not isinstance(context, pd.DataFrame) or context.empty:\n                context = res.get("candles")\n            if not isinstance(context, pd.DataFrame) or context.empty:\n                continue\n            pre, post, mode = _pair_for_target(context, pd.Timestamp(target_start))\n            if len(pre) < 2 or len(post) < 2:\n                continue\n            eng = _engine_from_pair(pre, post, label, {"scan_mode": mode})\n            b, a = eng.get("before", {}), eng.get("after", {})\n            rows.append({\n                "frame": label,\n                "actual_interval": _actual_interval(context),\n                "pre_rows": int(len(pre)),\n                "post_rows": int(len(post)),\n                "scan_mode": mode,\n                "before_move_%": b.get("move_%", 0),\n                "after_move_%": a.get("move_%", 0),\n                "before_buy_%": b.get("buy_%", 0),\n                "after_buy_%": a.get("buy_%", 0),\n                "before_sell_%": b.get("sell_%", 0),\n                "after_sell_%": a.get("sell_%", 0),\n                "before_fat_tail_z": b.get("fat_tail_z", 0),\n                "after_fat_tail_z": a.get("fat_tail_z", 0),\n                "before_kurtosis": b.get("kurtosis", 0),\n                "after_kurtosis": a.get("kurtosis", 0),\n                "before_dve_%": b.get("dve_%", 0),\n                "after_dve_%": a.get("dve_%", 0),\n                "reversal_strength": eng.get("weighted_score", 0),\n                "active_10_count": int(eng.get("active_count", 0)),\n                "raw_active_10_count": int(eng.get("raw_active_count", 0)),\n                "quality_score_v3": float(eng.get("quality_score_v3", 0)),\n                "quality_gate_v3": eng.get("quality_gate_v3", "BLOCK"),\n                "probability_%": int(eng.get("probability_pct", 0)),\n                "status": eng.get("status", "NORMAL"),\n                "capitulation_pattern": bool(eng.get("capitulation_pattern", False)),\n                "cause": " | ".join([str(r.get("driver")) for r in eng.get("drivers", []) if str(r.get("triggered")).upper() == "YES"]),\n            })\n        return pd.DataFrame(rows)\n\n    g["_evaluate_reversal_driver_from_values"] = _enhanced_reversal_eval\n    g["_loaded_reversal_history_df"] = _history_df\n    g["_reversal_pair_for_target"] = _pair_for_target\n    g["evaluate_latest_reversal_engine"] = _evaluate_latest\n    g["_find_last_reversal_threshold_time"] = _find_last\n    g["_finder_reversal_detector"] = _finder_detector\n'
